--
-- Table structure for table `biblio`
--

DROP TABLE IF EXISTS `biblio`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `biblio` (
  `biblionumber` int NOT NULL AUTO_INCREMENT COMMENT 'unique identifier assigned to each bibliographic record',
  `frameworkcode` varchar(4) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'foreign key from the biblio_framework table to identify which framework was used in cataloging this record',
  `author` longtext COLLATE utf8mb4_unicode_ci COMMENT 'statement of responsibility from MARC record (100$a in MARC21)',
  `title` longtext COLLATE utf8mb4_unicode_ci COMMENT 'title (without the subtitle) from the MARC record (245$a in MARC21)',
  `medium` longtext COLLATE utf8mb4_unicode_ci COMMENT 'medium from the MARC record (245$h in MARC21)',
  `subtitle` longtext COLLATE utf8mb4_unicode_ci COMMENT 'remainder of the title from the MARC record (245$b in MARC21)',
  `part_number` longtext COLLATE utf8mb4_unicode_ci COMMENT 'part number from the MARC record (245$n in MARC21)',
  `part_name` longtext COLLATE utf8mb4_unicode_ci COMMENT 'part name from the MARC record (245$p in MARC21)',
  `unititle` longtext COLLATE utf8mb4_unicode_ci COMMENT 'uniform title (without the subtitle) from the MARC record (240$a in MARC21)',
  `notes` longtext COLLATE utf8mb4_unicode_ci COMMENT 'values from the general notes field in the MARC record (500$a in MARC21) split by bar (|)',
  `serial` tinyint(1) DEFAULT NULL COMMENT 'Boolean indicating whether biblio is for a serial',
  `seriestitle` longtext COLLATE utf8mb4_unicode_ci,
  `copyrightdate` smallint DEFAULT NULL COMMENT 'publication or copyright date from the MARC record',
  `timestamp` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'date and time this record was last touched',
  `datecreated` date NOT NULL COMMENT 'the date this record was added to Koha',
  `abstract` longtext COLLATE utf8mb4_unicode_ci COMMENT 'summary from the MARC record (520$a in MARC21)',
  `opac_suppressed` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'whether the record should be suppressed in the OPAC',
  PRIMARY KEY (`biblionumber`),
  KEY `blbnoidx` (`biblionumber`),
  KEY `suppressedidx` (`opac_suppressed`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

