--
-- Table structure for table `letter`
--

DROP TABLE IF EXISTS `letter`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `letter` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'primary key identifier',
  `module` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'Koha module that triggers this notice or slip',
  `code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'unique identifier for this notice or slip',
  `branchcode` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'the branch this notice or slip is used at (branches.branchcode)',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'plain text name for this notice or slip',
  `is_html` tinyint(1) DEFAULT '0' COMMENT 'does this notice or slip use HTML (1 for yes, 0 for no)',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT 'subject line of the notice',
  `content` mediumtext COLLATE utf8mb4_unicode_ci COMMENT 'body text for the notice or slip',
  `message_transport_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'email' COMMENT 'transport type for this notice',
  `lang` varchar(25) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'default' COMMENT 'lang of the notice',
  `updated_on` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'last modification',
  `style` mediumtext COLLATE utf8mb4_unicode_ci COMMENT 'custom styles for this notice',
  PRIMARY KEY (`id`),
  UNIQUE KEY `letter_uniq_1` (`module`,`code`,`branchcode`,`message_transport_type`,`lang`),
  KEY `message_transport_type_fk` (`message_transport_type`),
  CONSTRAINT `message_transport_type_fk` FOREIGN KEY (`message_transport_type`) REFERENCES `message_transport_types` (`message_transport_type`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=110 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `letter`
--

LOCK TABLES `letter` WRITE;
/*!40000 ALTER TABLE `letter` DISABLE KEYS */;
INSERT INTO `letter` VALUES (1,'acquisition','ACQ_NOTIF_ON_RECEIV','','Notification on receiving',0,'Order received','Dear <<borrowers.firstname>> <<borrowers.surname>>,\r\n\r\n The order <<aqorders.ordernumber>> (<<biblio.title>>) has been received.\r\n\r\nYour library.','email','default','2026-05-25 05:28:27',NULL),(2,'bookings','BOOKING_CANCELLATION','','Booking cancellation notice',1,'A library booking was cancelled','[%- PROCESS \'html_helpers.inc\' -%]\r\n[%- USE KohaDates -%]\r\nDear [%- INCLUDE \'patron-title.inc\' patron => booking.patron -%],<br>\r\n<br>\r\nWe regret to inform you, that the following booking has been cancelled.<br>\r\n<br>\r\nTitle: [%- INCLUDE \'biblio-title.inc\' biblio=booking.biblio link = 0 -%]<br>\r\n<br>\r\nDates: [% booking.start_date | $KohaDates %] to [% booking.end_date | $KohaDates %]<br>\r\n<br>\r\nReason: [% booking.cancellation_reason | html %]<br>\r\n<br>\r\nKind regards<br>\r\n<br>\r\n[% booking.pickup_library.branchname %]','email','default','2026-05-25 05:28:27',NULL),(3,'bookings','BOOKING_MODIFICATION','','Booking modification notice',1,'A library booking was modified','[%- PROCESS \'html_helpers.inc\' -%]\r\n[%- USE KohaDates -%]\r\nDear [%- INCLUDE \'patron-title.inc\' patron => booking.patron -%],<br>\r\n<br>\r\nYour booking of [%- INCLUDE \'biblio-title.inc\' biblio=booking.biblio link = 0 -%] has been modified.<br>\r\n<br>\r\nThe new details are:<br>\r\n<br>\r\nDates: [% booking.start_date | $KohaDates %] to [% booking.end_date | $KohaDates %]<br>\r\n<br>\r\nPickup at: [% booking.pickup_library.branchname %]<br>\r\nKind regards<br>\r\n<br>\r\n[% booking.pickup_library.branchname %]','email','default','2026-05-25 05:28:27',NULL),(4,'bookings','BOOKING_CONFIRMATION','','Booking confirmation notice',1,'A library booking was confirmed','[%- PROCESS \'html_helpers.inc\' -%]\r\n[%- USE KohaDates -%]\r\nDear [%- INCLUDE \'patron-title.inc\' patron => booking.patron -%],<br>\r\n<br>\r\nYour booking of [%- INCLUDE \'biblio-title.inc\' biblio=booking.biblio link = 0 -%] has been confirmed.<br>\r\n<br>\r\nThe details are:<br>\r\n<br>\r\nDates: [% booking.start_date | $KohaDates %] to [% booking.end_date | $KohaDates %]<br>\r\n<br>\r\nPickup at: [% booking.pickup_library.branchname %]<br>\r\nKind regards<br>\r\n<br>\r\n[% booking.pickup_library.branchname %]','email','default','2026-05-25 05:28:27',NULL),(5,'catalogue','TICKET_ACKNOWLEDGE','','Concern acknowledgement',1,'Catalog concern acknowledgment','[%- PROCESS \'html_helpers.inc\' -%]\r\nDear [%- INCLUDE \'patron-title.inc\' patron => ticket.reporter -%],<br>\r\n<br>\r\nThank you for your report concerning [%- INCLUDE \'biblio-title.inc\' biblio=ticket.biblio link = 0 -%].<br>\r\n<br>\r\nYou reported: <br>\r\n[%- ticket.body -%]<br>\r\n<br>\r\nThank you','email','default','2026-05-25 05:28:27',NULL),(6,'catalogue','TICKET_ASSIGNED','','Concern assigned notification',1,'Catalog concern assigned','[%- PROCESS \'html_helpers.inc\' -%]\r\n[%- USE Koha -%]\r\nDear cataloger,<br>\r\n[%- INCLUDE \'patron-title.inc\' patron => librarian -%] has assigned the following concern with <a href=\'[%- Koha.Preference(\'staffClientBaseURL\') -%]/cgi-bin/koha/catalogue/detail.pl?biblionumber=[% ticket.biblio.biblionumber %]\' >[%- INCLUDE \'biblio-title.inc\' biblio=ticket.biblio link = 0 -%]</a> to you<br>\r\n<br>\r\n[%- ticket.body -%]<br>\r\n<br>\r\nYou can action this concern from the <a href=\'[%- Koha.Preference(\'staffClientBaseURL\') -%]/cgi-bin/koha/cataloguing/concerns.pl\'>concern management page</a>.','email','default','2026-05-25 05:28:27',NULL),(7,'catalogue','TICKET_RESOLVE','','Concern resolved',1,'Catalog concern resolved','[%- PROCESS \'html_helpers.inc\' -%]\r\nDear [%- INCLUDE \'patron-title.inc\' patron => ticket_update.ticket.reporter -%],<br>\r\n<br>\r\nThe library has now marked your concern with [%- INCLUDE \'biblio-title.inc\' biblio=ticket_update.ticket.biblio link = 0 -%] as resolved.<br>\r\n<br>\r\nThe following comment was left: <br>\r\n[%- ticket_update.message -%]<br>\r\n<br>\r\nThank you','email','default','2026-05-25 05:28:27',NULL),(8,'catalogue','TICKET_UPDATE','','Concern updated',1,'Catalog concern updated','[%- PROCESS \'html_helpers.inc\' -%]\r\nDear [%- INCLUDE \'patron-title.inc\' patron => ticket_update.ticket.reporter -%],<br>\r\n<br>\r\nThe library has added an update to the concern you reported against [%- INCLUDE \'biblio-title.inc\' biblio=ticket_update.ticket.biblio link = 0 -%].<br>\r\n<br>\r\nThe following comment was left: <br>\r\n[%- ticket_update.message -%]<br>\r\n<br>\r\nThank you','email','default','2026-05-25 05:28:27',NULL),(9,'catalogue','TICKET_NOTIFY','','Concern notification',1,'Catalog concern reported','[%- PROCESS \'html_helpers.inc\' -%]\r\n[%- USE Koha -%]\r\nDear cataloger,<br>\r\n[%- INCLUDE \'patron-title.inc\' patron => ticket.reporter -%] reported the following concern with <a href=\'[%- Koha.Preference(\'staffClientBaseURL\') -%]/cgi-bin/koha/catalogue/detail.pl?biblionumber=[% ticket.biblio.biblionumber %]\' >[%- INCLUDE \'biblio-title.inc\' biblio=ticket.biblio link = 0 -%]</a><br>\r\n<br>\r\n[%- ticket.body -%]<br>\r\n<br>\r\nYou can mark this concern as resolved from the <a href=\'[%- Koha.Preference(\'staffClientBaseURL\') -%]/cgi-bin/koha/cataloguing/concerns.pl\'>concern management page</a>.','email','default','2026-05-25 05:28:27',NULL),(10,'circulation','ACCOUNT_CREDIT','','Account payment',1,'Account payment','[%- USE AuthorisedValues -%]\r\n[%- USE KohaDates -%]\r\n[%- USE Price -%]\r\n[%- PROCESS \"accounts.inc\" -%]\r\n<table>\r\n    [% IF ( LibraryName ) %]\r\n    <tr>\r\n      <th colspan=\"2\" class=\"centerednames\">\r\n        <h3>[% LibraryName | html %]</h3>\r\n      </th>\r\n    </tr>\r\n    [% END %]\r\n    [% IF credit.library %]\r\n    <tr>\r\n      <th colspan=\"2\" class=\"centerednames\">\r\n        <h2>[% credit.library.branchname | html %]</h2>\r\n      </th>\r\n    </tr>\r\n    [% END %]\r\n    <tr>\r\n      <th colspan=\"2\" class=\"centerednames\">\r\n        <h3>[% today | $KohaDates %]</h3>\r\n      </th>\r\n    </tr>\r\n    <tr>\r\n      <td>Transaction ID: </td>\r\n      <td>[% credit.accountlines_id %]</td>\r\n    </tr>\r\n    <tr>\r\n      <td>Operator ID: </td>\r\n      <td>[% credit.manager_id %]</td>\r\n    </tr>\r\n    [% IF credit.payment_type %]\r\n    <tr>\r\n      <td>Payment type: </td>\r\n      <td>[% AuthorisedValues.GetByCode(\'PAYMENT_TYPE\', credit.payment_type) %]</td>\r\n    </tr>\r\n    [% END %]\r\n    <tr>\r\n      <th colspan=\"2\" class=\"centerednames\">\r\n        <h2><u>[%- PROCESS credit_type_description credit_type = credit.credit_type -%] receipt</u></h2>\r\n      </th>\r\n    </tr>\r\n    [% IF ( credit.credit_type_code == \'PAYMENT\' ) %]\r\n    <tr>\r\n      <th colspan=\"2\">\r\n        Received with thanks from  [% credit.patron.firstname | html %] [% credit.patron.surname | html %] <br>\r\n        Card number: [% credit.patron.cardnumber | html %]<br>\r\n      </th>\r\n    </tr>\r\n    [% ELSIF ( credit.credit_type_code == \'CREDIT\' ) %]\r\n    <tr>\r\n      <th colspan=\"2\">\r\n        Credit added to account for [% credit.patron.firstname | html %] [% credit.patron.surname | html %] <br>\r\n        Card number: [% credit.patron.cardnumber | html %]<br>\r\n      </th>\r\n    </tr>\r\n    [% ELSIF ( credit.credit_type_code == \'WRITEOFF\' ) %]\r\n    <tr>\r\n      <th colspan=\"2\">\r\n        Writeoff added to account for [% credit.patron.firstname | html %] [% credit.patron.surname | html %] <br>\r\n        Card number: [% credit.patron.cardnumber | html %]<br>\r\n      </th>\r\n    </tr>\r\n    [% END %]\r\n    [% IF credit.amountoutstanding + 0 != 0 %]\r\n    <tr>\r\n      <th>Description of credit</th>\r\n      <th>Amount</th>\r\n    </tr>\r\n    <tr>\r\n      <td>[%- PROCESS credit_type_description credit_type = credit.credit_type -%]</td>\r\n      <td>[% credit.amount * -1 | $Price %]</td>\r\n    </tr>\r\n    <tr>\r\n      <th style=\"text-align:right;\">Total available:</th>\r\n      <td>[% credit.amountoutstanding * -1 | $Price %]</td>\r\n    </tr>\r\n    [% END %]\r\n    [% IF credit.amount != credit.amountoutstanding %]\r\n    <tr>\r\n      <th>Description of charges</th>\r\n      <th>Amount</th>\r\n    </tr>\r\n    [% FOREACH offset IN credit.credit_offsets %]\r\n    <tr>\r\n      <td>[% PROCESS account_type_description account=offset.debit %][% IF ( offset.debit.itemnumber ) %] - [% offset.debit.item.biblio.title %][% END %]</td>\r\n      <td>[% offset.amount * -1 | $Price %]</td>\r\n    </tr>\r\n    [% END %]\r\n    [% END %]\r\n  <tfoot>\r\n    <tr class=\"highlight\">\r\n      <td>Total:</td>\r\n      <td>[% credit.amount * -1 | $Price %]</td>\r\n    </tr>\r\n    [% IF change.defined %]\r\n    <tr>\r\n      <td>Change given: </td>\r\n      <td>[% change | $Price %]</td>\r\n    </tr>\r\n    [% END %]\r\n    <tr>\r\n      <td colspan=\"2\"></td>\r\n    </tr>\r\n    <tr>\r\n      <td>Account balance as on date:</td>\r\n      <td>[% credit.patron.account.balance * -1 | $Price %]</td>\r\n    </tr>\r\n  </tfoot>\r\n</table>','print','default','2026-05-25 05:28:27',NULL),(11,'circulation','ACCOUNT_DEBIT','','Account fee',1,'Account fee','[% USE Price %]\r\n[% USE KohaDates %]\r\n[% PROCESS \"accounts.inc\" %]\r\n<table>\r\n    [% IF ( LibraryName ) %]\r\n    <tr>\r\n      <th colspan=\"3\" class=\"centerednames\">\r\n        <h3>[% LibraryName | html %]</h3>\r\n      </th>\r\n    </tr>\r\n    [% END %]\r\n    [% IF debit.library %]\r\n    <tr>\r\n      <th colspan=\"3\" class=\"centerednames\">\r\n        <h2>[% debit.library.branchname | html %]</h2>\r\n      </th>\r\n    </tr>\r\n    [% END %]\r\n    <tr>\r\n      <td colspan=\"2\" style=\"text-align:right;\">Fee ID: </td>\r\n      <td>[% debit.accountlines_id %]</td>\r\n    </tr>\r\n    [% IF credit.manager_id %]\r\n    <tr>\r\n      <td colspan=\"2\" style=\"text-align:right;\">Operator ID: </td>\r\n      <td>[% credit.manager_id %]</td>\r\n    </tr>\r\n    [% END %]\r\n    <tr>\r\n      <th colspan=\"3\" class=\"centerednames\">\r\n        <h2><u>Invoice</u></h2>\r\n      </th>\r\n    </tr>\r\n    <tr>\r\n      <th colspan=\"3\" >\r\n        Bill to: [% debit.patron.firstname | html %] [% debit.patron.surname | html %] <br>\r\n        Card number: [% debit.patron.cardnumber | html %]<br>\r\n      </th>\r\n    </tr>\r\n    [% IF debit.amountoutstanding != 0 %]\r\n    <tr>\r\n      <th>Date</th>\r\n      <th>Description of charges</th>\r\n      <th>Amount</th>\r\n    </tr>\r\n    <tr>\r\n      <td>[% debit.date | $KohaDates %]</td>\r\n      <td>[% PROCESS account_type_description account=debit %]</td>\r\n      <td>[% debit.amount | $Price %]</td>\r\n    </tr>\r\n    <tr>\r\n      <td colspan=\"2\" style=\"text-align:right;\">Total owed:</td>\r\n      <td>[% debit.amount | $Price %]</td>\r\n    </tr>\r\n    [% END %]\r\n    [% IF debit.amount != debit.amountoutstanding %]\r\n    <tr>\r\n      <th>Date</th>\r\n      <th>Description of payments</th>\r\n      <th>Amount</th>\r\n    </tr>\r\n    [% FOREACH offset IN debit.debit_offsets %]\r\n    <tr>\r\n      <td>[% offset.credit.date | $KohaDates %]</td>\r\n      <td>[% PROCESS account_type_description account=offset.credit %]</td>\r\n      <td>[% offset.amount * -1 | $Price %]</td>\r\n    </tr>\r\n    [% END %]\r\n    <tr class=\"highlight\">\r\n      <td colspan=\"2\" style=\"text-align:right;\">Total paid:</td>\r\n      <td>[% debit.amount - debit.amountoutstanding | $Price %]</td>\r\n    </tr>\r\n    [% END %]\r\n    </tr>\r\n      <td colspan=\"3\"></td>\r\n    <tr>\r\n  <tfoot>\r\n    <tr>\r\n      <th colspan=\"2\" style=\"text-align:right;\">Total outstanding:</th>\r\n      <td>[% debit.amountoutstanding | $Price %]</td>\r\n    </tr>\r\n  </tfoot>\r\n</table>','print','default','2026-05-25 05:28:27',NULL),(12,'circulation','ACCOUNT_PAYMENT','','Account payment',0,'Account payment','[%- USE Price -%]\r\nA payment of [% credit.amount * -1 | $Price %] has been applied to your account.\r\n\r\nThis payment affected the following fees:\r\n[%- FOREACH o IN offsets %]\r\nDescription: [% o.debit.description %]\r\nAmount paid: [% o.amount * -1 | $Price %]\r\nAmount remaining: [% o.debit.amountoutstanding | $Price %]\r\n[% END %]','email','default','2026-05-25 05:28:27',NULL),(13,'circulation','ACCOUNT_WRITEOFF','','Account writeoff',0,'Account writeoff','[%- USE Price -%]\r\nAn account writeoff of [% credit.amount * -1 | $Price %] has been applied to your account.\r\n\r\nThis writeoff affected the following fees:\r\n[%- FOREACH o IN offsets %]\r\nDescription: [% o.debit.description %]\r\nAmount paid: [% o.amount * -1 | $Price %]\r\nAmount remaining: [% o.debit.amountoutstanding | $Price %]\r\n[% END %]','email','default','2026-05-25 05:28:27',NULL),(14,'circulation','AR_CANCELED','','Article request - canceled',0,'Article request canceled','Dear <<borrowers.firstname>> <<borrowers.surname>> (<<borrowers.cardnumber>>),\r\n\r\nYour request for an article from <<biblio.title>> (<<items.barcode>>) has been canceled for the following reason:\r\n\r\n<<reason>>\r\n\r\nArticle requested:\r\nTitle: <<article_requests.title>>\r\nAuthor: <<article_requests.author>>\r\nVolume: <<article_requests.volume>>\r\nIssue: <<article_requests.issue>>\r\nDate: <<article_requests.date>>\r\nTOC: [% IF article_request.toc_request %]Yes[% ELSE %]No[% END %]\r\nPages: <<article_requests.pages>>\r\nChapters: <<article_requests.chapters>>\r\nNotes: <<article_requests.patron_notes>>\r\nFormat: [% IF article_request.format == \'PHOTOCOPY\' %]Copy[% ELSIF article_request.format == \'SCAN\' %]Scan[% END %]\r\n\r\nYour library','email','default','2026-05-25 05:28:27',NULL),(15,'circulation','AR_COMPLETED','','Article request - completed',0,'Article request completed','Dear <<borrowers.firstname>> <<borrowers.surname>> (<<borrowers.cardnumber>>),\r\n\r\nWe have completed your request for an article from <<biblio.title>> (<<items.barcode>>).\r\n\r\nArticle requested:\r\nTitle: <<article_requests.title>>\r\nAuthor: <<article_requests.author>>\r\nVolume: <<article_requests.volume>>\r\nIssue: <<article_requests.issue>>\r\nDate: <<article_requests.date>>\r\nTOC: [% IF article_request.toc_request %]Yes[% ELSE %]No[% END %]\r\nPages: <<article_requests.pages>>\r\nChapters: <<article_requests.chapters>>\r\nNotes: <<article_requests.patron_notes>>\r\nFormat: [% IF article_request.format == \'PHOTOCOPY\' %]Copy[% ELSIF article_request.format == \'SCAN\' %]Scan[% END %]\r\n\r\n[% IF article_request.format == \'PHOTOCOPY\' %]You may pick up your article at [% branch.branchname %].[% ELSIF article_request.format == \'SCAN\' %]You can download the scanned materials via the following URL(s): [% article_request.urls %].[% END %]\r\n\r\nThank you!','email','default','2026-05-25 05:28:27',NULL),(16,'circulation','AR_PENDING','','Article request - pending',0,'Pending article request','Dear <<borrowers.firstname>> <<borrowers.surname>> (<<borrowers.cardnumber>>)\r\n\r\nYour request for an article from <<biblio.title>> (<<items.barcode>>) is now in pending state.\r\n\r\nArticle requested:\r\nTitle: <<article_requests.title>>\r\nAuthor: <<article_requests.author>>\r\nVolume: <<article_requests.volume>>\r\nIssue: <<article_requests.issue>>\r\nDate: <<article_requests.date>>\r\nTOC: [% IF article_request.toc_request %]Yes[% ELSE %]No[% END %]\r\nPages: <<article_requests.pages>>\r\nChapters: <<article_requests.chapters>>\r\nNotes: <<article_requests.patron_notes>>\r\n\r\n\r\nThank you!','email','default','2026-05-25 05:28:27',NULL),(17,'circulation','AR_REQUESTED','','Article request - new',0,'Article request received','Dear <<borrowers.firstname>> <<borrowers.surname>> (<<borrowers.cardnumber>>)\r\n\r\nWe have received your request for an article from <<biblio.title>> (<<items.barcode>>).\r\n\r\nArticle requested:\r\nTitle: <<article_requests.title>>\r\nAuthor: <<article_requests.author>>\r\nVolume: <<article_requests.volume>>\r\nIssue: <<article_requests.issue>>\r\nDate: <<article_requests.date>>\r\nTOC: [% IF article_request.toc_request %]Yes[% ELSE %]No[% END %]\r\nPages: <<article_requests.pages>>\r\nChapters: <<article_requests.chapters>>\r\nNotes: <<article_requests.patron_notes>>\r\nFormat: [% IF article_request.format == \'PHOTOCOPY\' %]Copy[% ELSIF article_request.format == \'SCAN\' %]Scan[% END %]\r\n\r\nThank you!','email','default','2026-05-25 05:28:27',NULL),(18,'circulation','AR_PROCESSING','','Article request - processing',0,'Article request processing','Dear <<borrowers.firstname>> <<borrowers.surname>> (<<borrowers.cardnumber>>),\r\n\r\nWe are now processing your request for an article from <<biblio.title>> (<<items.barcode>>).\r\n\r\nArticle requested:\r\nTitle: <<article_requests.title>>\r\nAuthor: <<article_requests.author>>\r\nVolume: <<article_requests.volume>>\r\nIssue: <<article_requests.issue>>\r\nDate: <<article_requests.date>>\r\nTOC: [% IF article_request.toc_request %]Yes[% ELSE %]No[% END %]\r\nPages: <<article_requests.pages>>\r\nChapters: <<article_requests.chapters>>\r\nNotes: <<article_requests.patron_notes>>\r\nFormat: [% IF article_request.format == \'PHOTOCOPY\' %]Copy[% ELSIF article_request.format == \'SCAN\' %]Scan[% END %]\r\n\r\nThank you!','email','default','2026-05-25 05:28:27',NULL),(19,'circulation','AR_SLIP','','Article request - print slip',0,'Article request','Article request:\r\n\r\n<<borrowers.firstname>> <<borrowers.surname>> (<<borrowers.cardnumber>>),\r\n\r\nTitle: <<biblio.title>>\r\nBarcode: <<items.barcode>>\r\n\r\nArticle requested:\r\nTitle: <<article_requests.title>>\r\nAuthor: <<article_requests.author>>\r\nVolume: <<article_requests.volume>>\r\nIssue: <<article_requests.issue>>\r\nDate: <<article_requests.date>>\r\nTOC: [% IF article_request.toc_request %]Yes[% ELSE %]No[% END %]\r\nPages: <<article_requests.pages>>\r\nChapters: <<article_requests.chapters>>\r\nNotes: <<article_requests.patron_notes>>\r\nFormat: [% IF article_request.format == \'PHOTOCOPY\' %]Copy[% ELSIF article_request.format == \'SCAN\' %]Scan[% END %]','print','default','2026-05-25 05:28:27',NULL),(20,'circulation','CHECKIN','','Item check-in (digest)',0,'Check-ins','The following items have been checked in:\r\n----\r\n[% biblio.title %]\r\n----\r\nThank you.','email','default','2026-05-25 05:28:27',NULL),(21,'circulation','CHECKIN','','Item check-in (digest)',0,'Check-ins','The following items have been checked in:\r\n----\r\n[% biblio.title %]\r\n----\r\nThank you.','sms','default','2026-05-25 05:28:27',NULL),(22,'circulation','CHECKOUT','','Item check-out (digest)',0,'Checkouts','The following items have been checked out:\r\n----\r\n[% biblio.title %]\r\n----\r\nThank you for visiting [% branch.branchname %].','email','default','2026-05-25 05:28:27',NULL),(23,'circulation','CHECKOUT','','Item check-out (digest)',0,'Checkouts','The following items have been checked out:\r\n----\r\n[% biblio.title %]\r\n----\r\nThank you for visiting [% branch.branchname %].','sms','default','2026-05-25 05:28:27',NULL),(24,'circulation','CHECKOUT_NOTE','','Checkout note on item set by patron',0,'Checkout note','[% borrower.firstname %] [% borrower.surname %] has added a note to the item [% biblio.title %] by [% biblio.author %] ([% item.barcode %]):\r\n[% checkout.note %]','email','default','2026-05-25 05:28:27',NULL),(25,'circulation','DUE','','Item due reminder',0,'Item due reminder','Dear [% borrower.firstname %] [% borrower.surname %],\r\n\r\nThe following item is now due:\r\n\r\n[% biblio.title %], [% biblio.author %] ([% item.barcode %])','email','default','2026-05-25 05:28:27',NULL),(26,'circulation','DUE','','Item due reminder',0,'Item due reminder','Dear [% borrower.firstname %] [% borrower.surname %],\r\n\r\nThe following item is now due:\r\n\r\n[% biblio.title %]','sms','default','2026-05-25 05:28:27',NULL),(27,'circulation','DUEDGST','','Item due reminder (digest)',0,'Item due reminder','Dear [% borrower.firstname %