CREATE TABLE `serial` (
  `serialid` int NOT NULL AUTO_INCREMENT COMMENT 'unique key for the issue',
  `biblionumber` int NOT NULL COMMENT 'foreign key for the biblio.biblionumber that this issue is attached to',
  `subscriptionid` int NOT NULL COMMENT 'foreign key to the subscription.subscriptionid that this issue is part of',
