  `status` tinyint NOT NULL DEFAULT '0' COMMENT 'status code for this issue (see manual for full descriptions)',
  `planneddate` date DEFAULT NULL COMMENT 'date expected',
  `notes` mediumtext COLLATE utf8mb4_unicode_ci COMMENT 'notes',
  `publisheddate` date DEFAULT NULL COMMENT 'date published',
  `publisheddatetext` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'date published (descriptive)',
  `claimdate` date DEFAULT NULL COMMENT 'date claimed',
  `claims_count` int DEFAULT '0' COMMENT 'number of claims made related to this issue',
  `routingnotes` mediumtext COLLATE utf8mb4_unicode_ci COMMENT 'notes from the routing list',
  PRIMARY KEY (`serialid`),
  KEY `serial_ibfk_1` (`biblionumber`),
  KEY `serial_ibfk_2` (`subscriptionid`),
